const storage = $getWorkflowStaticData('global');
const input = $input.all()[0]?.json || {};
const userId = input.chatId || 'user_' + Date.now();
const userMsg = (input.userMessage || '').toLowerCase().trim();
const botResp = input.botResponse || {};

// Инициализация
if (!storage[userId]) {
  storage[userId] = {
    step: 1, // 1=спросить цель, 2=спросить уровень, 3=план готов, 4=отправка уроков
    goal: '',
    lessons: [],
    current: 0
  };
}

const user = storage[userId];
let response = {};

// ЛОГИКА
if (user.step === 1) {
  // Шаг 1: Спросить цель
  if (userMsg) {
    user.goal = userMsg;
    user.step = 2;
    response = { 
      action: 'ask_level', 
      message: 'Какой уровень: начинающий, средний?' 
    };
  } else {
    response = { 
      action: 'ask_goal', 
      message: 'Чему хочешь научиться?' 
    };
  }

} else if (user.step === 2) {
  // Шаг 2: Спросить уровень
  if (userMsg) {
    user.level = userMsg;
    user.step = 3;
    response = { 
      action: 'need_plan', 
      message: 'Создаю учебный план...' 
    };
  }

} else if (user.step === 3) {
  // Шаг 3: Обработка плана от AI
  if (botResp.topics) {
    user.lessons = botResp.topics.slice(0, 5); // Берем 5 тем
    user.step = 4;
    user.current = 0;

    response = {
      action: 'plan_ready',
      message: `🎯 План готов! ${user.lessons.length} тем.\n\nНапиши "да" чтобы начать.`
    };
  }

} else if (user.step === 4) {
  // Шаг 4: Ожидание "да" или отправка уроков

  if (userMsg === 'да') {
    // Пользователь подтвердил
    if (user.current < user.lessons.length) {
      const lesson = user.lessons[user.current];
      user.current++;

      response = {
        action: 'send_lesson',
        message: `📚 Урок ${user.current}: ${lesson}`,
        hasMore: user.current < user.lessons.length
      };

      if (user.current >= user.lessons.length) {
        user.step = 5;
        response.message += '\n\n🎉 Все уроки пройдены! Что дальше?';
      }
    }
  } else if (userMsg === 'дальше') {
    // Продолжаем уроки
    if (user.current < user.lessons.length) {
      const lesson = user.lessons[user.current];
      user.current++;

      response = {
        action: 'send_lesson',
        message: `📚 Урок ${user.current}: ${lesson}`,
        hasMore: user.current < user.lessons.length
      };

      if (user.current >= user.lessons.length) {
        user.step = 5;
        response.message += '\n\n🎉 Все уроки пройдены! Что дальше?';
      }
    }
  } else {
    response = {
      action: 'waiting_confirmation',
      message: 'Напиши "да" чтобы начать обучение!'
    };
  }

} else if (user.step === 5) {
  // Все завершено
  response = {
    action: 'completed',
    message: 'Готов учиться чему-то новому? Напиши что хочешь изучить!'
  };
  // Сброс
  delete storage[userId];
}

// Сохраняем
storage[userId] = user;

// Очистка
const keys = Object.keys(storage);
if (keys.length > 50) {
  delete storage[keys[0]];
}

return [{ json: response }];
